mapper.insert:
           INSERT INTO TB_WORD
           (
			 WORD_ID
			,WORD_NM			
			,WORD_ENG_ABRV_NM
			,WORD_ENG_NM		
			,WORD_DESC		
			,WORD_CLSF_YN	
			,DOMAIN_CLSF_NM	
			,ALLOPH_SYNM_LST	
			,FORBDN_WORD_LST	
			,COMM_STND_YN	
			,MAGNTD_ORD		
			,APRV_YN			
			,APRV_USER_ID	
			,CRET_DT			
			,CRET_USER_ID	
			,APRV_STAT_UPDT_DT
			,REQ_SYS_CD
           )
           VALUES
           (
             #{id}
            ,#{wordNm}
            ,#{wordEngAbrvNm}
            ,#{wordEngNm}
            ,#{wordDesc}
            ,#{wordClsfYn}
            ,#{domainClsfNm, jdbcType=VARCHAR}
            ,#{allophSynmLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
            ,#{forbdnWordLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
            ,#{commStndYn, jdbcType=VARCHAR}
            ,#{magntdOrd, jdbcType=VARCHAR}
            ,#{aprvYn, jdbcType=VARCHAR}
            ,#{aprvUserId, jdbcType=VARCHAR}
            ,to_char(now(), 'YYYYMMDDHH24MISS')
            ,#{cretUserId, jdbcType=VARCHAR}
			,to_char(now(), 'YYYYMMDDHH24MISS')
			,#{reqSysCd, jdbcType=VARCHAR}
		   )

mapper.update:
            UPDATE
              TB_WORD
            SET
               WORD_NM = #{wordNm}
              ,WORD_ENG_ABRV_NM = #{wordEngAbrvNm}
              ,WORD_ENG_NM = #{wordEngNm}
              ,WORD_DESC = #{wordDesc}
              ,WORD_CLSF_YN = #{wordClsfYn}
              ,DOMAIN_CLSF_NM = #{domainClsfNm}
              ,ALLOPH_SYNM_LST = #{allophSynmLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
              ,FORBDN_WORD_LST = #{forbdnWordLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
              ,COMM_STND_YN = #{commStndYn, jdbcType=VARCHAR}
              ,MAGNTD_ORD = #{magntdOrd, jdbcType=VARCHAR}
              ,UPDT_DT = to_char(now(), 'YYYYMMDDHH24MISS')
              ,UPDT_USER_ID = #{updtUserId, jdbcType=VARCHAR}
			  ,REQ_SYS_CD	= #{reqSysCd, jdbcType=VARCHAR}
            WHERE
              WORD_ID = #{id}
